type fakeHealth struct{ state telemetry.PathState }

func (f *fakeHealth) State() telemetry.PathState { return f.state }

// recordingRemote records the last endpoint SetPeerRemote was pointed at and how many
// times, standing in for the live Bind so the switch is observable without an engine.
type recordingRemote struct {
	last  netip.AddrPort
	calls int
}

func (r *recordingRemote) SetPeerRemote(ap netip.AddrPort) {
	r.last = ap
	r.calls++
}

func discardLogger(t *testing.T) log.Logger {
	t.Helper()
	lg, err := log.New("error", io.Discard)
	if err != nil {
		t.Fatalf("build logger: %v", err)
	}
	return lg
}

// discardInstall is the no-op install collaborator for controllers whose test never drives the
// FIRST-RESOLVE INSTALL PATH (boot adoption) — either the active spec is pre-seeded (activeSpec set
// at construction) or the case under test never boot-adopts. Tests that DO assert on the install
// pass a recording closure instead.
func discardInstall(netip.AddrPort) {}

